class Solution {
public:
    int maxConsecutiveAnswers(string answerKey, int k) {
        return max(maxConsecutive(answerKey, k, 'T'), maxConsecutive(answerKey, k, 'F'));
    }

    int maxConsecutive(string& answerKey, int k, char target) {
        int left = 0, maxLen = 0, count = 0;
        for (int right = 0; right < answerKey.size(); ++right) {
            count += (answerKey[right] != target);
            while (count > k) {
                count -= (answerKey[left] != target);
                left++;
            }
            maxLen = max(maxLen, right - left + 1);
        }
        return maxLen;
    }
};
